module RefModule(
input  [31:0] data_in, 
input          clk, clk_en,    
input          reset,start,  
input          sync,    
output [31:0] data_out 
);reg [31:0] obf_Q;




always @(posedge clk) 
begin
 if(reset)
  obf_Q <= 32'h00000000; 
 else 
 if(clk_en)
 begin
 if(start)
 begin
 if(sync)
  obf_Q <= data_in; 
  end
 end
end 

assign data_out = obf_Q;

endmodule
